/// <summary>
/// The class <c>ETG_SalesEditLines_Extension</c> is used to handle the COC methods related to <c>SalesEditLines</c> form.
/// </summary>
[ExtensionOf(formstr(SalesEditLines))]
final class ETG_SalesEditLines_Extension
{



}

Method.Source:
void  init()
{
    FormRun             formRun = this as  FormRun;

    next init();
    ETG_PostPackingQualityGrp   productReceiptQualityGrp;
    InventParameters            inventParameters;

    ttsbegin;
    update_recordset productReceiptQualityGrp
        setting ResultValue = 0
        where productReceiptQualityGrp.SalesId ==  salesFormLetter.salesTable().SalesId;
    ttscommit;

    select firstonly inventParameters;
    if (documentStatus == DocumentStatus::PackingSlip )
    {
        ETG_BLnumber.visible(false);
        ETG_BLDate.visible(false);
        ETG_BillOfLading.visible(true);
        Cocoa.visible(false);
        Cashew.visible(false);
    }
    else if(documentStatus == DocumentStatus::Invoice )
    {
        /* ETG_BLnumber.visible(true);
        ETG_BLDate.visible(true);
        ETG_BillOfLading.visible(false);*/
        if(inventParameters.ETGEnableQualityParameter == NoYes::Yes)
        {
            Cocoa.visible(true);
            Cashew.visible(true);
        }
    }
    else
    {
        ETG_BLnumber.visible(false);
        ETG_BLDate.visible(false);
        ETG_BillOfLading.visible(false);
        Cocoa.visible(false);
        Cashew.visible(false);
    }

}

void closeOk()
{
    FormRun             formRun = this as  FormRun;
    NoYes   BOlValidation =  ETG_Parameters::find().ETG_BLValidations;

    if (documentStatus == DocumentStatus::PackingSlip && BOlValidation)
    {
        FormDataSource      ETG_BillOfLading_ds = formRun.datasource(FormDatasourceStr(SalesEditLines, ETG_BillOfLading));
        ETG_BillOfLading    bol                 = ETG_BillOfLading_ds.Cursor();

        if(!bol.BOLNo)
        {
            throw error("@ETG:BOLNoValidationMsg");
        }

        if(!bol.BOLDate)
        {
            throw error("@ETG:BOLDateValidationMsg");
        }

        if(!bol.CarrierCode || !bol.CarrierId || !bol.PackageAppearanceText || !bol.PackageAppearanceText || !bol.NumberOfContainers || !bol.CreditDays ||
              !bol.DueDate || !bol.ImportPermitNumber || !bol.ImportDate || !bol.CargoInTransitTo || !bol.ContainerNumber || !bol.AgentSealNum || !bol.NetWeight || !bol.GrossWeight || !bol.NumberOfBags)
        {
            if(!( Box::yesNo("@ETG:ShippingDetValidationMsg" , DialogButton::Yes) == DialogButton::Yes))
            {
                throw error("@ETG:PostingCancelMsg");
            }
        }
    }
    /*else if(documentStatus == DocumentStatus::Invoice && BOlValidation)
    {
        FormDataSource      SalesParmTable_ds = formRun.dataSource(FormDatasourceStr(SalesEditLines, SalesParmTable));
        SalesParmTable      parmtable         = SalesParmTable_ds.cursor();

        if(!parmtable.ETG_BLnumber)
        {
            throw error("@ETG:BOLNoValidationMsg");
        }
    }*/

    if(ETGACFParameters::find().EnableSalesInvoiceWorkflow == NoYes::Yes)
    {
        FormDataSource      SalesParmLineDS = formRun.datasource(FormDatasourceStr(SalesEditLines,SalesParmLine));

        SalesParmLine SalesParmLineLoc = SalesParmLineDS.cursor();

        SalesParmUpdate  SalesParmUpdateloc = this.SalesParmUpdate;

        if(SalesParmLineLoc && SalesParmUpdateloc.SpecQty == SalesUpdate::PackingSlip)
        {
            ETGSalesEditLines ETGSalesEditLinesLocal;

            select firstonly ETGSalesEditLinesLocal
                where ETGSalesEditLinesLocal.PackingSlipId == SalesParmLineLoc.packingSlipId(SalesParmLineLoc)
                && ETGSalesEditLinesLocal.WorkflowStatus != ETGSalesEditLinesWorkflow::Approved;

            if(ETGSalesEditLinesLocal)
            {
                throw error("@ETG_New:ETGPackingSlipNotApproved");
            }

        }

    }
    infolog.clear();

    next closeOk();
}

