        // Fetch ETG_BillOfLading DataSource
        FormDataSource billOfLadingDS = formRun.dataSource(formDataSourceStr(SalesEditLines, ETG_BillOfLading));
        ETG_BillOfLading billLading = billOfLadingDS.cursor();


        ETG_BOLCarrierTable     carrierTable;
        CustPackingSlipJour     packingslipjour;
        CustPackingSlipTrans    packingsliptrans;

            //ttsBegin;



            //   while select forUpdate carrierTable
            //    where carrierTable.SalesId == salesParmTable.SalesId 

            //    if (carrierTable)
            //    {
            //        //carrierTable.PackingSlipId = packingSlipId;
            //        carrierTable.BOLId         = billLading.BOLNo;
            //        carrierTable.ParmId        = salesParmTable.ParmId;
            //        carrierTable.doUpdate();
            //    }
            //ttsCommit;
    }

    return canClose; 
}

